exercises.solution_code:
#include <iostream>
#include <utility>

int main()
{
    int n{};
    std::cin >> n;

    int* arr{ new int[n]{} };

    for (int i{ 0 }; i < n; ++i)
        std::cin >> arr[i];

    for (int front{ 0 }, back{ n - 1 }; front < back; ++front, --back)
        std::swap(arr[front], arr[back]);

    for (int i{ 0 }; i < n; ++i)
        std::cout << arr[i] << ' ';

    delete[] arr;
    return 0;
}

